package com.example.nofiltercoffee; import android.content.*; import android.view.*; import android.widget.*; import androidx.recyclerview.widget.*; import java.util.*;
public class SuggestionAdapter extends RecyclerView.Adapter<SuggestionAdapter.VH>{Context c;ArrayList<Product> list;Runnable cb;public SuggestionAdapter(Context c,ArrayList<Product> l,Runnable cb){this.c=c;list=l;this.cb=cb;} public VH onCreateViewHolder(ViewGroup p,int v){return new VH(LayoutInflater.from(p.getContext()).inflate(R.layout.item_suggestion,p,false));} public void onBindViewHolder(VH h,int p){Product pr=list.get(p);h.n.setText(pr.name);h.price.setText("Rs. "+pr.price);h.add.setOnClickListener(v->{if(ProductUtils.isDrink(pr.category)){Intent in=new Intent(c,ProductDetailActivity.class);in.putExtra("product",pr);c.startActivity(in);}else{CartManager.add(pr);if(cb!=null)cb.run();}});} public int getItemCount(){return Math.min(list.size(),8);} static class VH extends RecyclerView.ViewHolder{TextView n,price,add;VH(View v){super(v);n=v.findViewById(R.id.txtName);price=v.findViewById(R.id.txtPrice);add=v.findViewById(R.id.btnAdd);}}}
